    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Build the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<Product, "p">(
        "category"_t1,
        sqlgen::sum("quantity"_t2).as<"total_qty">,
        sqlgen::sum("amount"_t2).as<"total_amt">
    )
    | sqlgen::inner_join<Sale, "s">("product_id"_t1 == "product_id"_t2)
