    std::vector<CategoryReport> reports;
    for (const auto& row : result) {
        reports.push_back({
            row.category,
            static_cast<int>(row.total_qty),
            static_cast<double>(row.total_amt)
        });
    }

    return reports;
}

}  // namespace query_product_sales_report
