```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // 1. Create database connection
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Create tables
    conn.execute(sqlgen::to_sql(sqlgen::create_table<User>));
    conn.execute(sqlgen::to_sql(sqlgen::create_table<Friendship>));

    // 3. Insert data
    conn.execute(sqlgen::to_sql(sqlgen::insert(users)));
    conn.execute(sqlgen::to_sql(sqlgen::insert(friendships)));

    // 4. Query 1: Find mutual friends using SELF-JOIN
    auto mutual_friends_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::inner_join<User, Friendship>("u1"_t1, "f1"_t2, "u1"_t1.user_id == "f1"_t2.user_id1)
        | sqlgen::inner_join<Friendship, User>("f1"_t2, "u2"_t3, "f1"_t2.user_id2 == "u2"_t3.user_id)
        | sqlgen::where("u1"_t1.user_id < "u2"_t3.user_id)
        | sqlgen::select_from("u1"_t1.username, "u2"_t3.username);

    // 5. Query 2: Users with more than average friends using nested query
    auto avg_friends_subquery = sqlgen::read<std::vector<int>> 
        | sqlgen::select_from(sqlgen::count().as<"friend_count">)
        | sqlgen::group_by("user_id1"_t1);

    auto high_friend_count_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from("u1"_t1.username, sqlgen::count("f1"_t2.user_id2).as<"friend_count">)
        | sqlgen::left_join<Friendship>("f1"_t2, "u1"_t1.user_id == "f1"_t2.user_id1)
        | sqlgen::group_by("u1"_t1.user_id)
        | sqlgen::having(sqlgen::col<"friend_count"> > sqlgen::avg(avg_friends_subquery));

    // 6. Query 3: Friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::inner_join<User, Friendship>("u1"_t1, "f1"_t2, "u1"_t1.user_id == "f1"_t2.user_id1)
        | sqlgen::inner_join<Friendship, Friendship>("f1"_t2, "f2"_t3, "f1"_t2.user_id2 == "f2"_t3.user_id1)
        | sqlgen::inner_join<Friendship, User>("f2"_t3, "u2"_t4, "f2"_t3.user_id2 == "u2"_t4.user_id)
        | sqlgen::where("u1"_t1.user_id < "u2"_t4.user_id)
        | sqlgen::select_from("u1"_t1.username, "u2"_t4.username);

    // 7. Query 4: Count friends per user and identify most connected users
    auto friend_stats_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::select_from("u1"_t1.username, sqlgen::count("f1"_t2.user_id2).as<"friend_count">)
        | sqlgen::left_join<Friendship>("f1"_t2, "u1"_t1.user_id == "f1"_t2.user_id1)
        | sqlgen::order_by(sqlgen::desc(sqlgen::col<"friend_count">));

    // 8. Query 5: Users in same city not yet friends (recommendations)
    auto recommendation_query = sqlgen::read<std::vector<FriendConnection>>
        | sqlgen::inner_join<User, User>("u1"_t1, "u2"_t2, "u1"_t1.city == "u2"_t2.city)
        | sqlgen::where("u1"_t1.user_id < "u2"_t2.user_id && 
                       !sqlgen::exists(sqlgen::select_from(Friendship{}, 
                           sqlgen::where("f1"_t3.user_id1 == "u1"_t1.user_id && 
                                        "f1"_t3.user_id2 == "u2"_t2.user_id))))
        | sqlgen::select_from("u1"_t1.username, "u2"_t2.username);

    // Execute all queries and return combined results
    auto mutual_results = mutual_friends_query(conn).value();
    auto friend_of_friend_results = friend_of_friend_query(conn).value();
    auto recommendation_results = recommendation_query(conn).value();

    // Combine all results
    std::vector<FriendConnection> results;
    results.reserve(mutual_results.size() + friend_of_friend_results.size() + recommendation_results.size());

    results.insert(results.end(), mutual_results.begin(), mutual_results.end());
    results.insert(results.end(), friend_of_friend_results.begin(), friend_of_friend_results.end());
    results.insert(results.end(), recommendation_results.begin(), recommendation_results.end());

    return results;
}

}  // namespace analyze_social_network
