      inner_join<Customer, "c">(col<"customer_id", "o"> == col<"customer_id", "c">) |
      inner_join<Payment, "p">(col<"order_id", "o"> == col<"order_id", "p">) |
      order_by(col<"amount", "p">.desc()) | to<std::vector<Consolidated>>;

  return query(conn).value();
