```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = *conn_result;

  // Build the query using sqlgen's fluent interface
  auto query = select_from<Product>(
      "product_id"_c,
      "product_name"_c, 
      "category"_c,
      sum("price"_c * "quantity"_c) | as<"total_sales">
    )
    | inner_join<Sales>("product_id"_c == "product_id"_c)
    | group_by("product_id"_c, "product_name"_c, "category"_c)
    | order_by(desc("total_sales"_c))
    | limit(limit_count);

  // Execute the query and map results to TopProduct objects
  auto result = query(conn);
  if (!result) {
    return {}; // Return empty vector on query failure
  }

  // Convert the range to vector of TopProduct
  std::vector<TopProduct> top_products;
  for (auto& row : *result) {
    TopProduct tp{
      .product_id = std::get<0>(row),
      .product_name = std::get<1>(row),
      .category = std::get<2>(row),
      .total_sales = std::get<3>(row)
    };
    top_products.push_back(tp);
  }

  return top_products;
}

}  // namespace get_top_products
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Query Construction**: Uses sqlgen's fluent interface with `operator|` to build the query:
   - `select_from<Product>` starts the query on Product table
   - `inner_join<Sales>` performs the join with Sales table
   - `sum("price"_c * "quantity"_c) | as<"total_sales">` calculates total sales with proper aliasing
   - `group_by` groups by product fields
   - `order_by(desc("total_sales"_c))` sorts by total sales in descending order
   - `limit(limit_count)` applies the limit parameter

3. **Result Mapping**: Converts the query results to `TopProduct` objects by iterating through the range returned by the query execution

4. **Error Handling**: Returns empty vector on connection or query failures

The implementation follows sqlgen's principles of using a fluent interface with operator overloading to build SQL queries in a type-safe manner, while properly handling the aggregation, joining, grouping, and limiting operations as specified in the requirements.

