```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create select query from Source table, selecting the "value" column
    auto select_query = sqlgen::select_from<Source>("value"_c);

    // Apply where condition to filter records where value > 100
    auto filtered_query = select_query | sqlgen::where("value"_c > 100);

    // Create table Target from the select query
    auto create_query = sqlgen::create_as<Target>(filtered_query);

    return create_query;
}

}  // namespace create_table_as_select
```

## Explanation:

1. **`select_from<Source>("value"_c)`**: Creates a SELECT query from the `Source` table, selecting only the `value` column using the string literal operator `_c`.

2. **`| sqlgen::where("value"_c > 100)`**: Applies a WHERE condition using the pipe operator `|` to filter records where the `value` column is greater than 100.

3. **`sqlgen::create_as<Target>(filtered_query)`**: Creates a CREATE TABLE AS SELECT statement where the new `Target` table is populated with the results of the filtered query.

The function returns the query object, which can later be executed against a database connection to actually create the table.

This implementation follows the sqlgen library patterns shown in the reference materials, using the fluent interface with operator overloading (`|`) to build the query step by step.

